function segmentSum(nums: seq<int>, start: int, end: int): int
  requires 0 <= start <= end <= |nums|
  decreases end - start
{
  if start == end
  then 0
  else nums[start] + segmentSum(nums, start + 1, end)
}

predicate maxSubArrayPost(nums: seq<int>, maxSum: int)
  reads {}
{
  (exists s:int, e:int ::
      0 <= s < e <= |nums| &&
      segmentSum(nums, s, e) == maxSum) &&
  (forall i:int, j:int ::
      0 <= i < j <= |nums| ==> segmentSum(nums, i, j) <= maxSum)
}

// Lemma: segmentSum(nums, s, e+1) == segmentSum(nums, s, e) + nums[e]
// The recursive definition peels from the front; this lemma lets us extend from the end.
lemma segmentSumExtend(nums: seq<int>, s: int, e: int)
  requires 0 <= s <= e < |nums|
  ensures segmentSum(nums, s, e + 1) == segmentSum(nums, s, e) + nums[e]
  decreases e - s
{
  if s == e {
    // Base: segmentSum(nums, s, s+1) = nums[s] + segmentSum(nums, s+1, s+1) = nums[s] + 0 = nums[s]
    // and segmentSum(nums, s, s) + nums[s] = 0 + nums[s] = nums[s]
  } else {
    // segmentSum(nums, s, e+1) = nums[s] + segmentSum(nums, s+1, e+1)
    // By IH: segmentSum(nums, s+1, e+1) == segmentSum(nums, s+1, e) + nums[e]
    segmentSumExtend(nums, s + 1, e);
    // So segmentSum(nums, s, e+1) = nums[s] + segmentSum(nums, s+1, e) + nums[e]
    //                              = segmentSum(nums, s, e) + nums[e]
  }
}

// Lemma: if segmentSum(nums, s, e) <= maxSum for all s < e <= i,
// then extending by one element preserves the upper bound for segments ending at i+1,
// given that the max ending here (currentSum) <= maxSum.
// Actually, we need a more targeted lemma for the upper bound.

// Lemma: for any segment [s, e] where s < e <= i+1, segmentSum <= maxSum
// This follows from: for segments ending before i+1, we already know it.
// For segments ending exactly at i+1: segmentSum(nums, s, i+1) = segmentSum(nums, s, i) + nums[i]
// We need: max over s of segmentSum(nums, s, i+1) = max(currentSum_at_i + nums[i], nums[i])
// which is exactly what Kadane computes.

// Lemma: the max subarray ending at position e (exclusive) starting from some s,
// satisfies an optimal substructure property.
lemma segmentSumSplit(nums: seq<int>, s: int, m: int, e: int)
  requires 0 <= s <= m <= e <= |nums|
  ensures segmentSum(nums, s, e) == segmentSum(nums, s, m) + segmentSum(nums, m, e)
  decreases m - s
{
  if s == m {
    // segmentSum(nums, s, s) = 0, so result is 0 + segmentSum(nums, m, e) = segmentSum(nums, s, e)
  } else {
    // segmentSum(nums, s, e) = nums[s] + segmentSum(nums, s+1, e)
    // segmentSum(nums, s, m) = nums[s] + segmentSum(nums, s+1, m)
    // By IH: segmentSum(nums, s+1, e) = segmentSum(nums, s+1, m) + segmentSum(nums, m, e)
    segmentSumSplit(nums, s + 1, m, e);
  }
}

// Key lemma: if for all segments ending at position e (i.e., [s,e] for all valid s),
// segmentSum(nums, s, e) <= currentMax, and currentMax <= maxSum,
// then for all segments [s, e+1], segmentSum(nums, s, e+1) <= newCurrentMax
// where newCurrentMax = max(currentMax + nums[e], nums[e]).
// And the witness achieving newCurrentMax exists.

// Lemma: the best subarray ending at position `end` either starts at `end-1` (just nums[end-1])
// or extends the best subarray ending at `end-1`.
lemma bestEndingAt(nums: seq<int>, cs: int, end: int, currentSum: int)
  requires 0 <= cs < end <= |nums|
  requires segmentSum(nums, cs, end) == currentSum
  requires forall s :: 0 <= s < end ==> segmentSum(nums, s, end) <= currentSum
  ensures forall s :: 0 <= s < end + 1 ==> s < |nums| ==> end < |nums| ==>
    segmentSum(nums, s, end + 1) <= (if currentSum + nums[end] > nums[end] then currentSum + nums[end] else nums[end])
{
  // For any s where 0 <= s < end:
  //   segmentSum(nums, s, end+1) = segmentSum(nums, s, end) + nums[end]  (by segmentSumExtend)
  //                               <= currentSum + nums[end]
  // For s == end:
  //   segmentSum(nums, end, end+1) = nums[end]
  // So the max over all s in [0, end] of segmentSum(nums, s, end+1) is
  //   max(currentSum + nums[end], nums[end])
  if end < |nums| {
    var newEnd := end + 1;
    forall s | 0 <= s < newEnd
      ensures segmentSum(nums, s, newEnd) <= (if currentSum + nums[end] > nums[end] then currentSum + nums[end] else nums[end])
    {
      segmentSumExtend(nums, s, end);
      if s < end {
        // segmentSum(nums, s, end+1) = segmentSum(nums, s, end) + nums[end] <= currentSum + nums[end]
        assert segmentSum(nums, s, end) <= currentSum;
      } else {
        // s == end
        // segmentSum(nums, end, end+1) = nums[end]
      }
    }
  }
}

method maxSubArray(nums: seq<int>) returns (maxSum: int)
  requires |nums| >= 1
  ensures  maxSubArrayPost(nums, maxSum)
{
    var currentSum := nums[0];
    maxSum := nums[0];

    // Ghost variables to track witnesses
    ghost var cs := 0;    // start index for currentSum's segment: currentSum == segmentSum(nums, cs, i)
    ghost var ms := 0;    // start index for maxSum's segment
    ghost var me := 1;    // end index for maxSum's segment: maxSum == segmentSum(nums, ms, me)

    var i := 1;
    while i < |nums|
      invariant 1 <= i <= |nums|
      // currentSum is the max subarray sum ending at position i
      invariant 0 <= cs < i
      invariant currentSum == segmentSum(nums, cs, i)
      invariant forall s :: 0 <= s < i ==> segmentSum(nums, s, i) <= currentSum
      // maxSum is the global max subarray sum up to position i
      invariant 0 <= ms < me <= i
      invariant maxSum == segmentSum(nums, ms, me)
      invariant forall s, e :: 0 <= s < e <= i ==> segmentSum(nums, s, e) <= maxSum
      invariant currentSum <= maxSum
    {
        ghost var oldCurrentSum := currentSum;
        ghost var oldCs := cs;

        if currentSum + nums[i] > nums[i] {
            currentSum := currentSum + nums[i];
            // currentSum was segmentSum(nums, cs, i), now it's segmentSum(nums, cs, i) + nums[i]
            // which equals segmentSum(nums, cs, i+1)
            segmentSumExtend(nums, cs, i);
        } else {
            currentSum := nums[i];
            cs := i;
            // currentSum = nums[i] = segmentSum(nums, i, i+1)
        }

        // Prove: currentSum == segmentSum(nums, cs, i+1)
        // (already established above in each branch)

        // Prove: forall s :: 0 <= s < i+1 ==> segmentSum(nums, s, i+1) <= currentSum
        forall s | 0 <= s < i + 1
          ensures segmentSum(nums, s, i + 1) <= currentSum
        {
          segmentSumExtend(nums, s, i);
          if s < i {
            // segmentSum(nums, s, i+1) = segmentSum(nums, s, i) + nums[i]
            // segmentSum(nums, s, i) <= oldCurrentSum (from loop invariant)
            assert segmentSum(nums, s, i) <= oldCurrentSum;
            // So segmentSum(nums, s, i+1) <= oldCurrentSum + nums[i]
            if oldCurrentSum + nums[i] > nums[i] {
              // currentSum = oldCurrentSum + nums[i], and segmentSum(nums, s, i+1) <= oldCurrentSum + nums[i] = currentSum
            } else {
              // currentSum = nums[i], and oldCurrentSum + nums[i] <= nums[i]
              // So segmentSum(nums, s, i+1) = segmentSum(nums, s, i) + nums[i] <= oldCurrentSum + nums[i] <= nums[i] = currentSum
            }
          } else {
            // s == i, segmentSum(nums, i, i+1) = nums[i] <= currentSum
            // nums[i] <= currentSum because:
            // if branch taken: currentSum = oldCurrentSum + nums[i] > nums[i] (but actually >= nums[i] since > was the condition)
            //   wait, the condition was oldCurrentSum + nums[i] > nums[i], so currentSum = oldCurrentSum + nums[i] > nums[i]...
            //   but we need >=. Actually > implies >=.
            // else branch: currentSum = nums[i]
          }
        }

        if currentSum > maxSum {
            maxSum := currentSum;
            ms := cs;
            me := i + 1;
        }

        // Prove the global upper bound is maintained
        // For segments [s, e] where e <= i: already <= old maxSum <= new maxSum
        // For segments [s, i+1]: <= currentSum <= new maxSum

        assert forall s, e :: 0 <= s < e <= i + 1 ==> segmentSum(nums, s, e) <= maxSum by {
          forall s, e | 0 <= s < e <= i + 1
            ensures segmentSum(nums, s, e) <= maxSum
          {
            if e <= i {
              // From old invariant (need to be careful: old maxSum <= new maxSum)
            } else {
              // e == i + 1
              assert segmentSum(nums, s, i + 1) <= currentSum;
              assert currentSum <= maxSum;
            }
          }
        }

        i := i + 1;
    }

    // Post-condition: maxSubArrayPost(nums, maxSum)
    // exists: ms, me witness
    assert 0 <= ms < me <= |nums| && segmentSum(nums, ms, me) == maxSum;
    // forall: from the loop invariant at termination (i == |nums|)
    assert forall s, e :: 0 <= s < e <= |nums| ==> segmentSum(nums, s, e) <= maxSum;
}

